$path = "d:\BohraShaadi\dbohranisbat\src\components\RishtaDashboard.tsx"
$content = Get-Content $path -Raw
$oldBlock = "(?s)\{myProfile\.status === 'verified' && \(.*?Share Profile on WhatsApp.*?\}[\s\S]*?\)\}"
$newBlock = "{myProfile.status === 'verified' && (`n                                            <div className='flex flex-col gap-3 mt-6'>`n                                                <button`n                                                    id='download-biodata-btn'`n                                                    onClick={handleDownloadBiodata}`n                                                    disabled={generatingBiodata}`n                                                    className='w-full bg-gradient-to-r from-amber-500 to-orange-600 text-white py-3 rounded-xl text-sm font-black shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2 group active:scale-95'`n                                                >`n                                                    {generatingBiodata ? <RefreshCw className='w-4 h-4 animate-spin' /> : <Download className='w-4 h-4 group-hover:scale-110 transition-transform' />}`n                                                    Download PNG (Gallery Image)`n                                                </button>`n                                            </div>`n                                         )}"
$content = $content -replace $oldBlock, $newBlock
$content | Set-Content $path
